import React, { useState, useEffect } from 'react'
import { trackPromise } from 'react-promise-tracker'
import { Link } from 'react-router-dom'
import {
  CCardHeader,
  CCard,
  CCardBody,
  CTable,
  CTableHead,
  CTableRow,
  CTableHeaderCell,
  CTableBody,
  CTableDataCell,
  CBadge,
} from '@coreui/react'
import { getUser } from 'src/utils/Auth'
import LoadingIndicator from 'src/utils/LoadingIndicator'

const UnofficialApplications = () => {
  const [apps, setApps] = useState([])
  const user = getUser()

  useEffect(() => {
    getAppStat()
  }, [])

  const getAppStat = async () => {
    const resFromServer = await fetchStat()
    resFromServer ? setApps(resFromServer) : setApps(null)
  }

  const fetchStat = async () => {
    const res = await trackPromise(
      fetch(
        `https://records.run.edu.ng/api/app/my_student_applications?userid=${user.id}&matno=${user.matric_number}`,
      ),
    )
    const data = await res.json()
    return data
  }

  return (
    <>
      <CCard className="mb-4">
        <CCardHeader>
          <Link to="/application/form">Create New Application</Link>
        </CCardHeader>
        <CCardBody>
          <CTable responsive>
            <CTableHead color="dark">
              <CTableRow>
                <CTableHeaderCell scope="col">#</CTableHeaderCell>
                <CTableHeaderCell scope="col">Recipient</CTableHeaderCell>
                <CTableHeaderCell scope="col">Request Type</CTableHeaderCell>
                <CTableHeaderCell scope="col">Date</CTableHeaderCell>
                <CTableHeaderCell scope="col">Status</CTableHeaderCell>
              </CTableRow>
            </CTableHead>
            {apps ? (
              <CTableBody>
                {apps.map((item, index) => (
                  <CTableRow key={index}>
                    <CTableHeaderCell scope="row">{index + 1}</CTableHeaderCell>
                    <CTableDataCell>{item.recipient}</CTableDataCell>
                    <CTableDataCell>{item.transcript_type}</CTableDataCell>
                    <CTableDataCell>{new Date(item.created_at).toDateString()}</CTableDataCell>
                    <CTableDataCell>
                      {item.app_status === 'APPROVED' ? (
                        <CBadge color="success" shape="rounded-pill">
                          {item.app_status}
                        </CBadge>
                      ) : (
                        <CBadge color="secondary" shape="rounded-pill">
                          {item.app_status}
                        </CBadge>
                      )}
                    </CTableDataCell>
                  </CTableRow>
                ))}
              </CTableBody>
            ) : (
              <LoadingIndicator />
            )}
            <LoadingIndicator />
          </CTable>
        </CCardBody>
      </CCard>
    </>
  )
}

export default UnofficialApplications
